<template>
  <div style="width: 40%; margin-left: 200px">
    <div style="margin-bottom: 50px; margin-left: 280px" >新增出版社</div>
    <el-form :model="ruleForm" :rules="rules" ref="ruleForm" label-width="200px">
      <el-form-item label="姓名" prop="name">
        <el-input v-model="ruleForm.name" placeholder="请输入出版社名"></el-input>
      </el-form-item>
    </el-form>
    <div style="margin-left: 250px; margin-top: 40px">
      <el-button type="primary" @click="save">提交</el-button>
      <el-button style="background-color: #f3d19e; color: white" @click="change">返回</el-button>
      <!--            <el-button type="danger ">取消</el-button>-->
    </div>
  </div>
</template>

<script>
import request from "@/utils/request";
//导入请求
export default {
  name: "AddPublish",
  data(){
    const checkAge = (rule, value, callback) => {
      if (!value) {
        return callback(new Error('请输入年龄'));
      }

      if (!/^[0-9]+$/.test(value)) {
        callback(new Error('请输入数字值'));
      }
      if(parseInt(value) > 120 || parseInt(value) <= 0){
        callback(new Error('请输入合理年龄，年龄在1到120之间'));
      }
      callback();

    };
    const checkPhone = (rule, value, callback) => {

      if (!/^[1][3,4,5,6,7,8,9][0-9]{9}$/.test(value)) {
        callback(new Error('请输入合理的手机号，长度为11位数字'));
      }
      callback();

    };

    // 自定义的校验
    return {
      ruleForm: {

      },
      rules: {
        name: [
          {required: true, message: '请输入姓名', trigger: 'blur'},
          //trigger是失去焦点进行验证
          {min: 1, max: 10, message: '长度在 1 到 10 个字符', trigger: 'blur'}
        ],
        age:[
          { validator: checkAge, trigger: 'blur'}
        ],
        phone:[
          { validator: checkPhone, trigger: 'blur'}
        ],
        username: [
          {required: true, message: '请输入用户名', trigger: 'blur'},
          {min: 1, max: 10, message: '长度在 1 到 10 个字符', trigger: 'blur'}
        ]
      }
    }

  },
  methods: {
    save() {
      //this.$refs与ref关联的，可以获取dom元素和子组件实例，配合validate对整个表单进行校验，valid每个必填表单项都提交为true，否则为false，规范化的操作
      this.$refs['ruleForm'].validate((valid) => {
        if(valid){
          request.post('/publish/save',this.ruleForm).then(res =>{
            if(res.code === '200'){
              this.$notify.success('添加成功')
              // 重置表单
              this.$refs['ruleForm'].resetFields();
              this.$router.push('publishList');
            }else{
              this.$notify.error(res.msg)
            }
          })
        }
      })

    },
    change(){
      this.$router.push('publishList')
    }
  }
}
</script>

